import json

# Load the books data from the file path stored in var_functions.query_db:14
books_file_path = var_functions.query_db:14

books_with_years = []
with open(books_file_path, 'r') as f:
    books_with_years = json.load(f)

# Extract decade from year
processed_books = []
for book in books_with_years:
    try:
        year_float = float(book['year'])
        year = int(year_float)
        if 1000 <= year <= 2024:
            decade = (year // 10) * 10
            processed_books.append({
                'book_id': book['book_id'],
                'year': year,
                'decade': decade
            })
    except:
        continue

print('__RESULT__:')
print(json.dumps({
    'total_processed': len(processed_books),
    'sample_processed': processed_books[:5]
}))

