import json

# Access the query_db:14 result using string key
key = 'var_functions.query_db:14'
if key in locals():
    books_file_path = locals()[key]
    print('Got file path:', books_file_path)

    # Load the JSON
    with open(books_file_path, 'r') as f:
        books_data = json.load(f)

    # Process to extract decades
    processed = []
    for book in books_data:
        try:
            year_val = book.get('year')
            if year_val:
                year = int(float(year_val))
                if 1000 <= year <= 2024:
                    decade = (year // 10) * 10
                    processed.append({
                        'book_id': book['book_id'],
                        'decade': decade
                    })
        except:
            continue

    print('Total books with valid decades:', len(processed))
    print('Sample:', processed[:3])

    # Save for next step (we need to join with reviews later)
    # But just return summary for now
    result = {
        'total_books': len(processed),
        'decades': sorted(list(set([b['decade'] for b in processed]))),
        'sample': processed[:3]
    }
else:
    result = {'error': 'Key not found'}

print('__RESULT__:')
print(json.dumps(result))

